{"tool":"sql_query","args":{"query":"WITH top_v50d AS (SELECT calibration_id, engine_family, peak_power_kw, thermal_limit_deg_c FROM powertrain_calibration_specs WHERE lower(engine_family)=lower('V50D') ORDER BY CAST(peak_power_kw AS REAL) DESC, calibration_id ASC LIMIT 1), coolant_stats AS (SELECT COUNT(*) AS packs_exceed_15_l_min FROM battery_pack_module_specs WHERE CAST(coolant_flow_l_min AS REAL) > 15), max_coolant AS (SELECT pack_id AS max_coolant_pack_id, chemistry AS max_coolant_chemistry, peak_discharge_kw AS max_coolant_peak_discharge_kw, capacity_kwh AS max_coolant_capacity_kwh, usable_capacity_kwh AS max_coolant_usable_capacity_kwh, coolant_flow_l_min AS max_coolant_flow_l_min, heat_rejection_kw AS max_coolant_heat_rejection_kw FROM battery_pack_module_specs ORDER BY CAST(coolant_flow_l_min AS REAL) DESC, pack_id ASC LIMIT 1), max_heat AS (SELECT pack_id AS max_heat_pack_id, chemistry AS max_heat_chemistry, peak_discharge_kw AS max_heat_peak_discharge_kw, capacity_kwh AS max_heat_capacity_kwh, usable_capacity_kwh AS max_heat_usable_capacity_kwh, coolant_flow_l_min AS max_heat_coolant_flow_l_min, heat_rejection_kw AS max_heat_rejection_kw FROM battery_pack_module_specs ORDER BY CAST(heat_rejection_kw AS REAL) DESC, pack_id ASC LIMIT 1) SELECT t.calibration_id, t.engine_family, t.peak_power_kw, t.thermal_limit_deg_c, c.packs_exceed_15_l_min, mc.max_coolant_pack_id, mc.max_coolant_chemistry, mc.max_coolant_peak_discharge_kw, mc.max_coolant_capacity_kwh, mc.max_coolant_usable_capacity_kwh, mc.max_coolant_flow_l_min, mc.max_coolant_heat_rejection_kw, mh.max_heat_pack_id, mh.max_heat_chemistry, mh.max_heat_peak_discharge_kw, mh.max_heat_capacity_kwh, mh.max_heat_usable_capacity_kwh, mh.max_heat_coolant_flow_l_min, mh.max_heat_rejection_kw FROM top_v50d t CROSS JOIN coolant_stats c CROSS JOIN max_coolant mc CROSS JOIN max_heat mh","limit":5}}
